   106→  for (auto& filter : upstream_filters_) {
   107→    if (filter->filter_ != nullptr && filter->filter_->startUpstreamSecureTransport()) {
   108→      // Success. The filter converted upstream's transport socket to secure mode.
   109→      return true;
