   115→void FilterManagerImpl::maybeClose() {
   116→  if (connection_.state() == Connection::State::Closed) {
   117→    return;
   118→  }
   119→
   120→  ENVOY_CONN_LOG(trace,
   121→                 "maybeClose(): remote_close_pending_={}, local_close_pending_={}, "
   122→                 "filter_pending_close_count_={}",
   123→                 connection_, state_.remote_close_pending_, state_.local_close_pending_,
   124→                 state_.filter_pending_close_count_);
   125→
   126→  // Check if we need to close the connection
   127→  if (pendingClose() && state_.filter_pending_close_count_ == 0 &&
   128→      latched_close_action_.has_value()) {
   129→    state_.local_close_pending_ = false;
   130→    state_.remote_close_pending_ = false;
   131→    connection_.closeConnection(latched_close_action_.value());
   132→    return;
   133→  }
   134→}
