   228→void FilterManagerImpl::ActiveReadFilter::disableClose(bool disable) {
   229→  if (disable) {
   230→    // Handle the case where we are disabling the close
   231→    if (!pending_close_) {
   232→      pending_close_ = true;
   233→      parent_.state_.filter_pending_close_count_ += 1;
   234→    }
   235→  } else {
   236→    // Handle the case where we are re-enabling the close
   237→    if (pending_close_) {
   238→      pending_close_ = false;
   239→      parent_.state_.filter_pending_close_count_ -= 1;
   240→    }
   241→
   242→    if (parent_.state_.filter_pending_close_count_ == 0) {
   243→      parent_.maybeClose();
   244→    }
   245→  }
   246→}
