164→ConnPoolImplBase::tryCreateNewConnection(float global_preconnect_ratio) {
   165→  // There are already enough Connecting connections for the number of queued streams.
   166→  if (!shouldCreateNewConnection(global_preconnect_ratio)) {
   167→    return ConnectionResult::ShouldNotConnect;
   168→  }
   169→  ENVOY_LOG(trace, "creating new preconnect connection");
   170→
   171→  const bool can_create_connection = host_->canCreateConnection(priority_);
   172→
   173→  if (!can_create_connection) {
   174→    host_->cluster().trafficStats()->upstream_cx_overflow_.inc();
   175→  }
   176→  // If we are at the connection circuit-breaker limit due to other upstreams having
   177→  // too many open connections, and this upstream has no connections, always create one, to
   178→  // prevent pending streams being queued to this upstream with no way to be processed.
   179→  if (can_create_connection || (ready_clients_.empty() && busy_clients_.empty() &&
   180→                                connecting_clients_.empty() && early_data_clients_.empty())) {
   181→    ENVOY_LOG(debug, "creating a new connection (connecting={})", connecting_clients_.size());
   182→    ActiveClientPtr client = instantiateActiveClient();
   183→    if (client.get() == nullptr) {
   184→      ENVOY_LOG(trace, "connection creation failed");
   185→      return ConnectionResult::FailedToCreateConnection;
   186→    }
   187→    ASSERT(client->state() == ActiveClient::State::Connecting);
   188→    ASSERT(std::numeric_limits<uint64_t>::max() - connecting_stream_capacity_ >=
   189→           static_cast<uint64_t>(client->currentUnusedCapacity()));
   190→    ASSERT(client->real_host_description_);
   191→    // Increase the connecting capacity to reflect the streams this connection can serve.
   192→    incrConnectingAndConnectedStreamCapacity(client->currentUnusedCapacity(), *client);
   193→    LinkedList::moveIntoList(std::move(client), owningList(client->state()));
   194→    assertCapacityCountsAreCorrect();
   195→    return can_create_connection ? ConnectionResult::CreatedNewConnection
   196→                                 : ConnectionResult::CreatedButRateLimited;
   197→  } else {
   198→    ENVOY_LOG(trace, "not creating a new connection: connection constrained");
   199→    return ConnectionResult::NoConnectionRateLimited;
   200→  }
   201→}
